plist.dict:
Label
{{{ID}}}-mvrk-baker-next

UserName
{{{USER}}}
GroupName
{{{USER}}}

ProgramArguments

    {{{ROOT_DIR}}}/bin/baker-next
    --remote-signer
    {{{model.REMOTE_SIGNER_ADDR}}}
    run
    with
    local
    node
    {{{ROOT_DIR}}}/data/.mavryk-node
    {{{model.KEY_ALIASES}}}
    --votefile
    {{{ROOT_DIR}}}/data/vote-file.json
    {{#configuration.BAKER_STARTUP_ARGS}}
    {{{.}}}
    {{/configuration.BAKER_STARTUP_ARGS}}


EnvironmentVariables

    HOME
    {{{ROOT_DIR}}}/data
    MAVRYK_LOG
    * -> {{{model.BAKER_LOG_LEVEL}}}


WorkingDirectory
{{{ROOT_DIR}}}/data

KeepAlive

ThrottleInterval
1

StandardOutPath
/usr/local/var/log/{{{ID}}}-mvrk-baker-next.log
StandardErrorPath
/usr/local/var/log/{{{ID}}}-mvrk-baker-next.log

{{#model.SERVICE_CONFIGURATION__ARRAY}}
{{{key}}}
{{{value}}}
{{/model.SERVICE_CONFIGURATION__ARRAY}}
